// Extract error metadata and redact anything that looks like a secret.
// Logged output must never expose API keys, license keys, buyer emails,
// or raw customer data.
const SECRET_PATTERNS = [
  new RegExp('sk' + '-[A-Za-z0-9_-]{10,}', 'g'),
  new RegExp('xox' + 'b-[A-Za-z0-9-]{10,}', 'g'),
  new RegExp('gh' + 'p_[A-Za-z0-9]{20,}', 'g'),
  new RegExp('github' + '_pat_[A-Za-z0-9_]{20,}', 'g'),
  new RegExp('AKIA' + '[0-9A-Z]{16}', 'g'),
  new RegExp('Bearer\\s+[A-Za-z0-9._~+/-]{15,}', 'gi'),
  new RegExp('[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\\.[A-Za-z]{2,}', 'g'),
];

function sanitize(value) {
  let out = String(value == null ? '' : value);
  for (const pattern of SECRET_PATTERNS) {
    out = out.replace(pattern, '[REDACTED]');
  }
  return out.slice(0, 2000);
}

const results = [];
for (const item of $input.all()) {
  const data = item.json || {};
  const execution = data.execution || {};
  const workflow = data.workflow || {};
  const error = execution.error || {};
  results.push({
    json: {
      logged_at: new Date().toISOString(),
      workflow_id: workflow.id || 'unknown',
      workflow_name: workflow.name || 'unknown',
      execution_id: execution.id || 'unknown',
      execution_url: sanitize(execution.url || ''),
      execution_mode: execution.mode || 'unknown',
      failed_node: execution.lastNodeExecuted || 'unknown',
      error_message: sanitize(error.message || 'No error message provided'),
      error_description: sanitize(error.description || ''),
    },
  });
}
return results;

